  },
};

export class GeminiLiveService {
  private client: GoogleGenAI;
  private session: any = null;
  private onUpdate: (params: Partial<VisualParams>, message: string) => void;

  constructor(apiKey: string, onUpdate: (params: Partial<VisualParams>, message: string) => void) {
    this.client = new GoogleGenAI({ apiKey });
    this.onUpdate = onUpdate;
  }

  async connect() {
    const config = {
      model: 'gemini-2.5-flash-native-audio-preview-09-2025',
      callbacks: {
        onopen: () => {
          console.log('[Gemini] Session Opened');
        },
        onmessage: (message: LiveServerMessage) => {
          this.handleMessage(message);
        },
        onclose: () => {
          console.log('[Gemini] Session Closed');
        },
        onerror: (e: any) => {
          console.error('[Gemini] Error:', e);
        }
      },
      config: {
        responseModalities: [Modality.AUDIO], // We mostly want tool calls, but audio is required
        tools: [{ functionDeclarations: [updateVisualsFunction] }],
        systemInstruction: `
          You are the core logic of a "TouchDesigner" style audio-visualizer. 
          Your input is a video stream of a user.
          Analyze the user's hand gestures to control the visual parameters:

          1. **Geometry**: 
             - Closed Fist -> CUBE
             - Open Palm / Spread Fingers -> ICOSPHERE
             - Peace Sign (V) -> TORUS
             - 1 Finger -> TETRAHEDRON

          2. **Complexity (Detail)**:
             - Closer to camera -> Lower detail
             - Further from camera -> Higher detail

          3. **Rotation Speed**:
             - Fast hand movement -> Fast rotation
             - Still hand -> Slow rotation

          4. **Color**:
             - Change color based on the position of the hand in the frame (Left=Cool colors, Right=Warm colors).

          Call the 'updateVisuals' tool frequently (every 1-2 seconds) to reflect changes. 
          Be precise and responsive.
        `,
      }
    };

    this.session = await this.client.live.connect(config);
  }

  async sendVideoFrame(base64Data: string) {
    if (!this.session) return;

    // Clean base64 string if it has the prefix
    const data = base64Data.replace(/^data:image\/(png|jpeg);base64,/, "");

    try {
      await this.session.sendRealtimeInput({
        media: {
          mimeType: 'image/jpeg',
          data: data
        }
      });
    } catch (e) {
      console.error("Error sending frame", e);
    }
  }

  private handleMessage(message: LiveServerMessage) {
    // Check for Tool Calls
    if (message.toolCall) {
      for (const fc of message.toolCall.functionCalls) {
        if (fc.name === 'updateVisuals') {
          const args = fc.args as any;
          this.onUpdate(args, args.statusMessage || "Updating...");

          // Must send response back
          this.session.sendToolResponse({
            functionResponses: {
              id: fc.id,
              name: fc.name,
              response: { result: "ok" }
            }
          });
        }
      }
    }
  }

  disconnect() {
    // There is no explicit disconnect on the session object in the current SDK version shown in docs,
    // usually we just stop sending data or let it timeout, but if close exists:
    // @ts-ignore
    if (this.session && typeof this.session.close === 'function') {
      // @ts-ignore
      this.session.close();
    }
    this.session = null;
  }
}

import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment } from '@react-three/drei';
import * as THREE from 'three';
import { GeometryType, VisualParams } from '../types';
import { AudioAnalyzer } from '../services/audioAnalyzer';

interface SceneProps {
  params: VisualParams;
  analyzer: AudioAnalyzer | null;
}

const ReactiveMesh: React.FC<{ params: VisualParams; analyzer: AudioAnalyzer | null }> = ({ params, analyzer }) => {
  const meshRef = useRef<THREE.Mesh>(null);

  // Create geometry based on params
  const geometry = useMemo(() => {
    switch (params.geometry) {
      case GeometryType.CUBE:
        return new THREE.BoxGeometry(2, 2, 2, params.detail + 1, params.detail + 1, params.detail + 1);
      case GeometryType.ICOSPHERE:
        return new THREE.IcosahedronGeometry(1.5, params.detail);
      case GeometryType.TORUS:
        return new THREE.TorusGeometry(1.2, 0.4, 8 + params.detail * 2, 20 + params.detail * 5);
      case GeometryType.TETRAHEDRON:
        return new THREE.TetrahedronGeometry(1.8, params.detail);
      default:
        return new THREE.IcosahedronGeometry(1.5, 0);
    }
  }, [params.geometry, params.detail]);

  useFrame((state, delta) => {
    if (!meshRef.current) return;

    // 1. Rotation
    const speed = params.rotationSpeed * 0.1;
    meshRef.current.rotation.x += delta * speed;
    meshRef.current.rotation.y += delta * speed * 0.5;

    // 2. Audio Reactivity (Scale & Distortion pulse)
    if (analyzer) {
      const freq = analyzer.getFrequencyData(); // 0-255
      const bass = analyzer.getBassEnergy();

      const scaleBase = 1;
      const scaleFactor = (bass / 255) * params.distortionFactor; // Normalize 0-1 then multiply by factor

      const targetScale = scaleBase + scaleFactor * 0.5;

      // Smooth lerp for scale
      meshRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.1);

      // Jitter rotation slightly on high frequencies
      if (freq > 200) {
        meshRef.current.rotation.z += (Math.random() - 0.5) * 0.1 * params.distortionFactor;
      }
    }
  });

  return (
    <mesh ref={meshRef} geometry={geometry}>
      <meshPhysicalMaterial
        color={params.colorHex}
        wireframe={params.wireframe}
        metalness={params.metalness}
        roughness={params.roughness}
        clearcoat={1.0}
        clearcoatRoughness={0.1}
        flatShading={params.geometry === GeometryType.TETRAHEDRON || params.detail < 1}
      />
    </mesh>
  );
};

const Scene3D: React.FC<SceneProps> = ({ params, analyzer }) => {
  return (
    <Canvas>
      <PerspectiveCamera makeDefault position={[0, 0, 5]} />
      <OrbitControls enableZoom={false} enablePan={false} />

      <ambientLight intensity={0.2} />
      <pointLight position={[10, 10, 10]} intensity={1} color="#00ffcc" />
      <pointLight position={[-10, -10, -10]} intensity={0.5} color="#ff00ff" />
      <spotLight position={[0, 10, 0]} angle={0.3} penumbra={1} intensity={1} />

      <ReactiveMesh params={params} analyzer={analyzer} />

      <Environment preset="city" />

      {/* Post-processing feel via simple overlay/fog */}
      <fog attach="fog" args={['#050505', 5, 15]} />
    </Canvas>
  );
};

export default Scene3D;

