// Default Params
const DEFAULT_PARAMS: VisualParams = {
  geometry: GeometryType.ICOSPHERE,
  detail: 1,
  wireframe: true,
  rotationSpeed: 1,
  colorHex: '#00ffff',
  metalness: 0.8,
  roughness: 0.2,
  distortionFactor: 1.0,
};

const App: React.FC = () => {
  const [params, setParams] = useState<VisualParams>(DEFAULT_PARAMS);
  const [active, setActive] = useState(false);
  const [status, setStatus] = useState("System Standby");
  const [apiKey, setApiKey] = useState<string>("");
  const [showApiKeyModal, setShowApiKeyModal] = useState(true);

  // Refs for non-react state
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const geminiServiceRef = useRef<GeminiLiveService | null>(null);
  const analyzerRef = useRef<AudioAnalyzer>(new AudioAnalyzer());
  const frameIntervalRef = useRef<number | null>(null);

  // Initialize environment
  useEffect(() => {
    // Check for pre-existing key (though unlikely in this environment)
    if (process.env.API_KEY) {
      setApiKey(process.env.API_KEY);
      setShowApiKeyModal(false);
    }
  }, []);

  const handleStart = async () => {
    if (!apiKey) {
      alert("API Key Required");
      return;
    }

    try {
      setStatus("Initializing Hardware...");
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      streamRef.current = stream;

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.play();
      }

      // Initialize Audio
      await analyzerRef.current.initialize(stream);
      analyzerRef.current.resume();

      // Initialize Gemini
      setStatus("Connecting to Neuro-Core (Gemini)...");
      geminiServiceRef.current = new GeminiLiveService(apiKey, (newParams, msg) => {
        setParams(prev => ({ ...prev, ...newParams }));
        setStatus(msg.toUpperCase());
      });

      await geminiServiceRef.current.connect();
      setStatus("LINK ESTABLISHED. AWAITING INPUT.");
      setActive(true);

      // Start Frame Loop
      startVisionLoop();

    } catch (err) {
      console.error(err);
      setStatus("CRITICAL ERROR: Hardware/Connection Failed");
      setActive(false);
    }
  };

  const startVisionLoop = () => {
    if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);

    // Send frame every 1s (balance latency vs rate limits/token usage)
    frameIntervalRef.current = window.setInterval(async () => {
      if (!canvasRef.current || !videoRef.current || !geminiServiceRef.current) return;

      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      canvasRef.current.width = 320; // Downscale for bandwidth
      canvasRef.current.height = 240;
      ctx.drawImage(videoRef.current, 0, 0, 320, 240);

      const base64 = canvasRef.current.toDataURL('image/jpeg', 0.6);
      await geminiServiceRef.current.sendVideoFrame(base64);
    }, 1000);
  };

  const handleStop = () => {
    setActive(false);
    setStatus("System Offline");
    if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop());
    }
    geminiServiceRef.current?.disconnect();
    analyzerRef.current.cleanup();
  };

  // API Key Modal
  if (showApiKeyModal) {
    return (
      <div className="fixed inset-0 bg-black flex items-center justify-center p-4 z-50 font-mono text-cyan-400">
        <div className="max-w-md w-full border border-cyan-800 bg-[#0a0a0a] p-8 shadow-[0_0_20px_rgba(0,255,255,0.1)] relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500 to-transparent opacity-50"></div>
          <h1 className="text-2xl font-bold mb-6 tracking-widest text-center">NEURO_GEO_INIT</h1>
          <p className="mb-4 text-xs text-cyan-700">SECURE TERMINAL ACCESS // ENTER KEY</p>
          <input 
            type="password" 
            placeholder="PASTE GEMINI API KEY"
            className="w-full bg-[#111] border border-cyan-900 p-3 text-cyan-100 outline-none focus:border-cyan-500 mb-6 font-mono text-sm transition-colors"
            value={apiKey}
            onChange={(e) => setApiKey(e.target.value)}
          />
          <button 
            onClick={() => apiKey && setShowApiKeyModal(false)}
            className="w-full bg-cyan-900/20 hover:bg-cyan-900/40 border border-cyan-700 text-cyan-400 py-3 uppercase tracking-widest text-sm transition-all hover:shadow-[0_0_15px_rgba(0,255,255,0.2)]"
          >
            Authenticate
          </button>
          <p className="mt-4 text-[10px] text-zinc-600 text-center">
             This application requires the Gemini Live API (Multimodal).<br/>
             Keys are not stored persistently.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-screen bg-[#050505] text-cyan-500 font-mono overflow-hidden">
      {/* Hidden Video/Canvas for Processing */}
      <video ref={videoRef} className="hidden" muted playsInline />
      <canvas ref={canvasRef} className="hidden" />

      {/* 3D Scene Background */}
      <div className="absolute inset-0 z-0">
        <Scene3D params={params} analyzer={analyzerRef.current} />
      </div>

      {/* UI Overlay - TouchDesigner Style */}
      <div className="absolute inset-0 z-10 pointer-events-none p-4 flex flex-col justify-between">

        {/* Header */}
        <div className="flex justify-between items-start">
          <div className="border border-cyan-900 bg-black/80 backdrop-blur-sm p-4 w-64">
            <h1 className="text-xl font-bold tracking-tighter mb-1 text-white">NEURO.GEO</h1>
            <div className="text-[10px] text-cyan-700 mb-2">GENERATIVE INTERFACE v0.9.1</div>
            <div className="h-px w-full bg-cyan-900 mb-2"></div>
            <div className="flex items-center gap-2 text-xs">
              <span className={`w-2 h-2 rounded-full ${active ? 'bg-green-500 animate-pulse' : 'bg-red-900'}`}></span>
              <span>{status}</span>
            </div>
          </div>

          <div className="border border-cyan-900 bg-black/80 backdrop-blur-sm p-2 pointer-events-auto">
             {!active ? (
               <button onClick={handleStart} className="px-6 py-2 bg-cyan-900/30 hover:bg-cyan-500/20 border border-cyan-500/50 text-cyan-300 text-sm transition-all">
                 INITIALIZE SYSTEM
