             ) : (
               <button onClick={handleStop} className="px-6 py-2 bg-red-900/30 hover:bg-red-500/20 border border-red-500/50 text-red-300 text-sm transition-all">
                 TERMINATE
               </button>
             )}
          </div>
        </div>

        {/* Center Crosshair (Aesthetic) */}
