// Default Params
const DEFAULT_PARAMS: VisualParams = {
  geometry: GeometryType.ICOSPHERE,
  detail: 1,
  wireframe: true,
  rotationSpeed: 1,
  colorHex: '#00ffff',
  metalness: 0.8,
  roughness: 0.2,
  distortionFactor: 1.0,
};

